Set the base path to your repository name (`/KRR-virtualacademy/`) so GitHub Pages can find the assets.

```ts
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

// https://vitejs.dev/config/
export default defineConfig({
  plugins: [react()],
  // Set base to the repository name for GitHub Pages.
  // This fixes the blank white screen by ensuring scripts load from the correct sub-folder.
  base: '/KRR-virtualacademy/', 
});
```

